#!/usr/bin/env node
// Builds scripts/seeds/aetrex-orthotic-tree.json from a master-index
// JSON produced upstream (see /tmp/master-index.json — generated by
// the python xlsx parser; the parser is intentionally NOT in the
// repo because the source spreadsheet isn't either, this script is
// the deterministic transform from "list of master SKUs" to "tree
// shape the engine consumes").
//
// Usage:
//   node scripts/build-aetrex-orthotic-tree.mjs <master-index.json>
//
// Output is the JSON document for DecisionTree.definition.

import { readFileSync, writeFileSync } from "node:fs";
import { resolve, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const here = dirname(fileURLToPath(import.meta.url));
const masterPath = process.argv[2] || resolve(here, "../master-index.json");
const masterIndex = JSON.parse(readFileSync(masterPath, "utf8"));

const definition = {
  rootNodeId: "q_gender",

  // Order matters: the engine walks nodes following `next` links;
  // skipIfKnown lets gender (or anything else) be pre-filled by the
  // existing choice-button system in chat.jsx.
  nodes: [
    {
      id: "q_gender",
      type: "question",
      attribute: "gender",
      skipIfKnown: true,
      question: "Who are these orthotics for?",
      chips: [
        { label: "Men", value: "Men" },
        { label: "Women", value: "Women" },
        { label: "Boys", value: "Boys" },
        { label: "Girls", value: "Girls" },
        { label: "Kids", value: "Kids" },
      ],
      next: {
        Men:   "q_use_case",
        Women: "q_use_case",
        Boys:  "q_kids_use_case",
        Girls: "q_kids_use_case",
        Kids:  "q_kids_use_case",
      },
    },

    {
      id: "q_use_case",
      type: "question",
      attribute: "useCase",
      question: "What kind of shoes will the orthotics go in?",
      chips: [
        { label: "Dress shoes",                          value: "dress" },
        { label: "Dress shoes (no removable insole)",    value: "dress_no_removable" },
        { label: "Premium dress shoes",                  value: "dress_premium" },
        { label: "Everyday / casual shoes",              value: "casual" },
        { label: "Athletic — running",                   value: "athletic_running" },
        { label: "Athletic — gym / training",            value: "athletic_training" },
        { label: "Athletic — court / general",           value: "athletic_general" },
        { label: "Cleats",                               value: "cleats" },
        { label: "Hockey skates",                        value: "skates" },
        { label: "Winter boots",                         value: "winter_boots" },
        { label: "Work / on my feet all day",            value: "work_all_day" },
        { label: "Just want comfort / relief",           value: "comfort" },
      ],
      next: { _default: "q_condition" },
    },

    {
      id: "q_kids_use_case",
      type: "question",
      attribute: "useCase",
      question: "What kind of shoes will they go in?",
      chips: [
        { label: "Sport / athletic shoes", value: "kids" },
        { label: "Casual shoes",           value: "kids" },
        { label: "Dress shoes",            value: "kids" },
      ],
      // Kids tree resolves immediately. Aetrex's kids line doesn't
      // differentiate by overpronation/met-support; arch is filled
      // from defaults. Keeps the parent UX to two taps.
      next: { _default: "q_resolve" },
    },

    {
      id: "q_condition",
      type: "question",
      attribute: "condition",
      question: "Any specific foot pain or condition we should match?",
      chips: [
        { label: "Plantar fasciitis",                  value: "plantar_fasciitis" },
        { label: "Heel spurs",                         value: "heel_spurs" },
        { label: "Ball-of-foot pain / metatarsalgia", value: "metatarsalgia" },
        { label: "Morton's neuroma",                   value: "mortons_neuroma" },
        { label: "Overpronation / flat feet",          value: "overpronation_flat_feet" },
        { label: "Diabetic feet",                      value: "diabetic" },
        { label: "None — just want comfort",           value: "none" },
      ],
      next: { _default: "q_arch" },
    },

    {
      id: "q_arch",
      type: "question",
      attribute: "arch",
      question: "What's your arch type?",
      chips: [
        { label: "Flat / Low",                         value: "Flat / Low Arch" },
        { label: "Medium",                             value: "Medium / High Arch" },
        { label: "High",                               value: "Medium / High Arch" },
        { label: "I don't know",                       value: "Medium / High Arch" },
      ],
      next: {
        "Flat / Low Arch":     "q_resolve",  // flat already implies posted via derivation
        "Medium / High Arch":  "q_overpronation",
      },
    },

    {
      id: "q_overpronation",
      type: "question",
      attribute: "overpronation",
      question:
        "When you walk or stand, do your ankles roll inward or do you have flat-feet symptoms?",
      chips: [
        { label: "Yes",     value: "yes" },
        { label: "No",      value: "no" },
        { label: "Not sure", value: "no" },
      ],
      next: { _default: "q_resolve" },
    },

    { id: "q_resolve", type: "resolve" },
  ],

  // Aetrex spec, confirmed by merchant:
  //   posted = (arch == Flat) OR (overpronation == "yes")
  //   metSupport = condition is one of {ball-of-foot, mortons, metatarsalgia}
  derivations: [
    {
      set: "posted",
      value: true,
      when: {
        any: [
          { attr: "arch", eq: "Flat / Low Arch" },
          { attr: "overpronation", eq: "yes" },
        ],
      },
    },
    {
      set: "posted",
      value: false,
      when: {
        all: [
          { attr: "arch", eq: "Medium / High Arch" },
          { attr: "overpronation", eq: "no" },
        ],
      },
    },
    {
      set: "metSupport",
      value: true,
      when: {
        any: [
          { attr: "condition", eq: "metatarsalgia" },
          { attr: "condition", eq: "mortons_neuroma" },
        ],
      },
    },
  ],

  resolver: {
    // Confirmed defaults: unknown arch → Medium/High (the larger
    // half of the line, biomechanically safer for an unknown foot).
    defaults: {
      arch: "Medium / High Arch",
      posted: false,
      metSupport: false,
      condition: "none",
    },
    masterIndex,
    fallback: {
      // If a customer somehow lands in an empty cell (shouldn't
      // happen given key cell coverage), surface the unisex Edge
      // orthotic — universal fit, pleasant default.
      masterSku: "L1800U",
      title: "Unisex Edge Orthotics",
      reason: "no exact match — universal default",
    },
  },
};

const out = resolve(here, "seeds/aetrex-orthotic-tree.json");
writeFileSync(out, JSON.stringify(definition, null, 2) + "\n");
console.log(`Wrote ${out} (${masterIndex.length} masters indexed)`);
